var b="url",c="款式归档操作_新增_.html",d="generationDate",e=new Date(1781589185558.48),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="Water",s="PreVerStatus",t="page",u="packageId",v="e2d30ebdd197439899cb373ba71ded29",w="type",x="Axure:Page",y="款式归档操作(新增)",z="notes",A="annotations",B="fn",C="1",D="ownerId",E="ec61856277114409821a38cb46777599",F="label",G="按版单号归档",H="说明",I="<p><span>1.数据源：以该款号进行打样的版单号</span></p><p><span>2.每次选择版单后，同步版单的版单类型至“归档类型”</span></p><p><span>3.选择完后，二次弹窗确认是否使用该版单的数据。将选中版单的最新“已提交”版本作为当前[可编辑]的数据（不考虑当前用户的[</span><span style=\"color:#333333;\">样衣开发任务设置</span><span>]权限，直接调取打样单对应各项TAB的数据）</span></p><p><span>4.[颜色尺码]中的数据取的是打样单的颜色尺码，其他页签中的数据，都是一一对应取版单对应的TAB</span></p>",J="2",K="1bf6a7997e3041a996ab513e7951887d",L="* 归档类型",M="<p><span>1.数据源：数据字典-样衣类型配置（system_config_SAMPLE_NAME）</span></p><p><span>2.每次选择版单号后，将版单的版单类型同步过来</span></p>",N="3",O="dd5b5dde09ba41be84e2b16298133716",P="添加",Q="<p><span>对填写的文本进行校验；若匹配已存在，Toast提示：尺码重复</span></p>",R="4",S="2e23d7e437484f5aa60531319d56852e",T="(下拉列表)",U="<p><span>1.提示语：</span><span style=\"color:#333333;\">请选择新增成衣颜色</span></p><p><span>2.支持模糊搜索 &quot;成衣颜色”</span></p>",V="5",W="7d503d89ed224f29b85c28ab854dba01",X="<p><span>对选中的成衣颜色进行校验；若匹配已存在，Toast提示：颜色重复</span></p>",Y="6",Z="fdaf5539ad4f47adac030f8f7d62ee0c",ba="保存",bb="<p><span>1.提示：请选择“归档类型”</span></p><p><span>2.提示：请填写“归档说明”</span></p><p><span>3.保存时校验“设置尺码”是否为空，否则Toast提示：请设置归档尺码</span></p><p><span>4.保存时校验“设置颜色”是否为空，否则Toast提示：请设置归档颜色</span></p><p><span>5.同时相当于所有tab都用保存校验一下</span></p><p><span>&nbsp;&nbsp;&nbsp; a.[尺寸表]：尺寸清单内若有空白行，保存后自动移除</span></p><p><span>&nbsp;&nbsp;&nbsp; b.[版型文件]：①裁片列表判断“数量”列，提示：数量须为正整数；②裁片列表内若有空白行，保存后自动移除</span></p><p><span>&nbsp;&nbsp;&nbsp; c.[物料明细]：校验“来源”、“工段”、“物料颜色”、“物料规格”不能为空</span></p><p><span>&nbsp;&nbsp;&nbsp; d.[工序工价]：①校验“工序类型”必填 ②校验“标准工时(秒)”、“工价1~3”均保留2位小数 ③若有空白行，保存后自动移除</span></p><p><span>&nbsp;&nbsp;&nbsp; e.[成本核价]：①校验“价格”保留两位小数②附加成本清单内若有空白行，保存后自动移除</span></p><p><span>4.归档版本号：'V'+'递增数字'+'-'+'款号'，例如V2-kuanhao001</span></p>",bc="7",bd="49f5ffc595c9491898ab893017979531",be="建档物料",bf="<p><span>1.尺码列来源于[颜色尺码]中设置的“归档尺码”</span></p><p><span>2.成衣颜色来源于[颜色尺码]中设置的“归档颜色”</span></p><p><span>3.该表交互同生产物料的BOM3</span></p>",bg="8",bh="ec1f11dac9fe4afaa92b94d9035b032c",bi="类型",bj="<p><span>拉取选择的物料的属性</span></p>",bk="9",bl="170ec157c1284107b54e9ca9edfa72ed",bm="含税单价",bn="<p><span>保留三位小数</span></p>",bo="10",bp="1341f5ef563646fba91358fba028cfbb",bq="税率(%)",br="<p><span>整数</span></p>",bs="11",bt="1314fe0ff8b84fadaec9fb3d542a89ed",bu="未税单价",bv="12",bw="759c52547d39495d9cafa6c1e6796af2",bx="来源",by="<p><span>0-厂供(默认)</span></p><p><span>1-客供</span></p><p><span>2-客指</span></p>",bz="13",bA="434a84fcc7c042fda09b3c91ab8fb9d7",bB="新增一行",bC="<p><span>1.来源默认“厂供”</span></p><p><span>2.工段默认总体安排内[工段设置]的第一个</span></p>",bD="14",bE="c139f2fdab27447497aa884bd629eb79",bF="确认",bG="<p><span>在[采购管理系统-采购需求-找样需求]生成一条找样单</span></p>",bH="15",bI="b354610c2bb549249711572e0eaa011c",bJ="导入",bK="<p><span>TXT导入：</span></p><p><span>以制图软件导出的txt为标准</span></p><p><span>EXCEL：</span></p><p><span>1.导入格式与表头保持一致</span></p><p><span>2.CODE、部位：文本格式</span></p><p><span>3.档差、尺码、公差：保留1位的数字格式；若填写非数字，同样导入成功，该字段无值</span></p>",bL="16",bM="7a26d2a1670b41bcab77a346d2dc1e69",bN="CODE",bO="<p><span>“尺码列”固定为[颜色尺码]内设置的归档尺码</span></p>",bP="17",bQ="28d9e92164c0417f84a8bcc91af6679f",bR="基础码",bS="<p><span>1.该选项内，选中的尺码为基础码。基础码在列上须要标志出来，与其他尺码进行区分，如图所示</span></p><p><span>2.数据源：该版单打样清单内的尺码</span></p>",bT="18",bU="07ac5744eaee4700830c7b6957827601",bV="推码",bW="<p><span>1.点击判断档差列必须＞0，否则提示“档差须大于0”</span></p><p><span>2.二次确认</span></p><p><span>3.推码逻辑：以选中的基础码及档差按尺码顺序进行推码</span></p><p><span>&nbsp;&nbsp;&nbsp; a.基础码往左列的数据依次按档差递减</span></p><p><span>&nbsp;&nbsp;&nbsp; b.基础码往右列的数据依次按档差递增</span></p>",bX="19",bY="89a3ef7ad609431e986fd4768bad6ea7",bZ="TCS001.prj",ca="<p><span>1. 点击可下载(若权限许可)</span></p><p><span>2.格式可以是任意格式文档(常见图片格式除外)</span></p>",cb="20",cc="bbd9020331ad4c93a16566353d4986e9",cd="编辑",ce="<p><span>最多一份文件，每次上传效果为覆盖当前文件</span></p>",cf="21",cg="97eb09b54a3140b8bdcc9dcee42b98d2",ch="<p><span>校验权限名称是否唯一</span></p><p><span>否则提示“权限名称已存在”</span></p>",ci="22",cj="ac1c116910384d07bcd1bc21820a6bc9",ck="<p><span>获取本地文件</span></p>",cl="23",cm="fcef964a73fe45f9b8895c096e2e414c",cn="<p><span>原txt文件</span></p>",co="24",cp="1fd5795f236d4874bab07eb0462bb3e6",cq="数量",cr="<p><span>正整数</span></p>",cs="25",ct="eefb804586ba4bc6a50d9d50f6913156",cu="(形状)",cv="<p><span>1.点击直接获取本地文件</span></p><p><span>2.根据上传的文件是否为图片格式，进行不同的展示</span></p>",cw="26",cx="13c3dae2b4134f5bbb391cb9dfc7d11d",cy="一键生成",cz="<p><span>1.清空工序表已填写的数据</span></p><p><span>2.将[总体安排]中工段设置中，每个工段一条数据填充进工序表</span></p>",cA="27",cB="fcefd6248d694e1e82b67400b7a1ca84",cC="价格(单件成衣)",cD="<p><span>保留两位小数</span></p>",cE="28",cF="e2a47de808294794a245949edd6f0da9",cG="成本核算",cH="<p><span>成本核算内的价格列均需实时更新</span></p><p><span>1.物料成本来自于[物料信息]内单色单码的含税价格*单耗</span></p><p><span>2.工序成本为工序表中合计的金额（不区分颜色、尺码）</span></p><p><span>3.附加成本为当前页填写的各项价格的合计金额（不区分颜色、尺码）</span></p><p><span>4.单件成本=单色单码的“物料成本”+“工序成本”+“附加成本”</span></p>",cI="29",cJ="e298dd54ef8a47d0b79530bb44368356",cK="工序成本",cL="<p><span>工序表中保存后生效的合计的金额（不区分颜色、尺码）</span></p>",cM="30",cN="e6c1bd312307468c8fb81c9aa7807e63",cO="附加成本",cP="<p><span>附加成本为当前页填写的各项价格保存后的合计金额（不区分颜色、尺码）</span></p>",cQ="31",cR="c92d857a292a4584a5986c84de634e61",cS="物料成本",cT="<p><span>物料成本来自于[物料信息]内保存后生效的单色单码的含税价格*单耗</span></p>",cU="32",cV="c8944a7057694cf0a7c48881100d7227",cW="单件成本",cX="<p><span>1.根据各项成本实时计算</span></p><p><span>2.单件成本=单行“物料成本”+“工序成本”+“附加成本”</span></p>",cY="33",cZ="8bc7cbd2bb424c758bc00d64838d28b3",da="序号",db="<p><span>1.层级总共包含两级，两级均为物料行</span></p><p><span>2.左侧的“+”和“-”按钮用来展开和收拢展示数据</span></p><p><span>3.初始进入页面，只展示一级的物料信息</span></p>",dc="34",dd="bc5d4d2313f24fdebcf5b2315ed5a5af",de="* 单耗：",df="<p><span>数字格式，保留两位小数</span></p>",dg="35",dh="392cb4aab1cb4ef39e388e76d87cf453",di="损耗(%)：",dj="36",dk="02760ca067824ab19e56c466e44e84a0",dl="* 物料颜色：",dm="<p><span>1. 数据源：系统中所有[物料颜色]，可进行模糊搜索颜色和色号</span></p><p><span>2. “颜色”字体颜色区分标识： 若在物料明细中：蓝色 ； 颜色库中但非物料明细中：黑色</span></p>",dn="37",dp="764d82bf63ad4715a6c5635452c443c6",dq="* 规格/门幅：",dr="<p><span>1. 数据源：物料明细中该物料已创建的规格</span></p><p><span>2. 展示样式：“规格”(“克重”)</span></p>",ds="38",dt="9790fbc700574b63a68594e8e7ce9a08",du="* 物料名称：",dv="<p><span>1.支持模糊搜索启用的“物料编码”和“物料名称”</span></p><p><span>2.选中物料后，自动带出该物料的第一个SKU的 规格/门幅(克重)-物料颜色；未生成SKU的物料仅将当前的“规格/门幅”和“物料颜色”清空</span></p>",dw="39",dx="3a6e3de946bb4d1d82a1f3411ab5e344",dy="<p><span>1.校验“物料名称”、“规格”、“颜色”、“单耗”的必填</span></p><p><span>2.若“单耗”或“损耗(%)”的值超出两位小数，确认时自动用四舍五入方式保留至2位</span></p><p><span>3.若是不存在的SKU，自动按当前选中的 物料编码-规格-物料颜色 生成新的SKU</span></p>",dz="40",dA="927128adbf404df6abfbb54481a7e6eb",dB="关联定制：",dC="<p><span>1.数据源：当前款式在[款式定制项]中，“关联物料”为“是”的[选项组名-选项名称]</span></p><p><span>2.下拉支持模糊搜索“选项组名”或“选项名称”</span></p><p><span>3.最好记录id，防止那边“选项组名”或“选项名称”变更后找不到</span></p>",dD="41",dE="d954be5919ef477995cfb6f065226a8a",dF="操作",dG="<p><span>1.层级总共包含两级，两级均为物料行</span></p><p><span>2.一级的可“增加子项”；二级的不可“增加子项”</span></p>",dH="42",dI="8c6479c8185d4d03a9a0765c44ea23b8",dJ="新建",dK="<p><span>每次新建的都为“一级”的物料</span></p>",dL="43",dM="9e8d62ef77ff4679a93f330777268fd4",dN="44",dO="b6109f6cb31d43009fefd69c62ec13a1",dP="<p><span>1.不考虑当前用户的[</span><span style=\"color:#333333;\">样衣开发任务设置</span><span>]权限，直接调取打样单对应各项TAB的数据</span></p><p><span>2.[颜色尺码]中的数据取的是打样单的颜色尺码</span></p><p><span>3.其他页签中的数据，都是一一对应取版单对应的TAB</span></p>",dQ="style",dR="baseStyle",dS="627587b6038d43cca051c114ac41ad32",dT="pageAlignment",dU="center",dV="fill",dW="fillType",dX="solid",dY="color",dZ=0xFFFFFFFF,ea="image",eb="imageAlignment",ec="near",ed="imageRepeat",ee="auto",ef="favicon",eg="sketchFactor",eh="0",ei="colorStyle",ej="appliedColor",ek="fontName",el="Applied Font",em="borderWidth",en="borderVisibility",eo="borderFill",ep=0xFF797979,eq="cornerRadius",er="cornerVisibility",es="outerShadow",et="on",eu=false,ev="offsetX",ew=5,ex="offsetY",ey="blurRadius",ez="spread",eA="r",eB=0,eC="g",eD="b",eE="a",eF=0.349019607843137,eG="adaptiveStyles",eH="interactionMap",eI